AdvertConfig = {}
AdvertConfig.GoldAds = {}
AdvertConfig.ShopAds = {}
AdvertConfig.GiftAds = {}
AdvertConfig.ChestAds = {}
AdvertConfig.VipAds = {}

function AdvertConfig:initConfig(adverts)
    for _, item in pairs(adverts) do
        local advert = {}
        advert.id = tonumber(item.id)
        advert.count = tonumber(item.count)
        advert.seconds = tonumber(item.seconds)
        if tonumber(item.type) == Define.AdType.Gold then
            table.insert(self.GoldAds, advert)
        elseif (tonumber(item.type) == Define.AdType.Shop) then
            table.insert(self.ShopAds, advert)
        elseif (tonumber(item.type) == Define.AdType.Gift) then
            table.insert(self.GiftAds, advert)
        elseif (tonumber(item.type) == Define.AdType.FreeChest) then
            table.insert(self.ChestAds, advert)
        elseif (tonumber(item.type) == Define.AdType.FreeVip) then
            table.insert(self.VipAds, advert)
        end
    end
    table.sort(self.GoldAds, function(a, b)
        return a.id < b.id
    end)
    table.sort(self.ShopAds, function(a, b)
        return a.id < b.id
    end)
    table.sort(self.GiftAds, function(a, b)
        return a.id < b.id
    end)
    table.sort(self.ChestAds, function(a, b)
        return a.id < b.id
    end)
    table.sort(self.VipAds, function(a, b)
        return a.id < b.id
    end)
end

function AdvertConfig:initPlayerAds(player)
    if player.advert_record == nil then
        player.advert_record = {
            DayKey = "",
            GoldAdTimes = 0,
            ShopAdTimes = 0,
            GameAdTimes = 0,
            GiftAdTimes = 0,
            ChestAdTimes = 0,
            VipAdTimes = 0
        }
    end
    local key = DateUtil.getYearDay()
    if player.advert_record.DayKey ~= key then
        player.advert_record = {
            DayKey = key,
            GoldAdTimes = 0,
            ShopAdTimes = 0,
            GameAdTimes = 0,
            GiftAdTimes = 0,
            ChestAdTimes = 0,
            VipAdTimes = 0
        }
    end
    self:syncGoldAdInfo(player)
    self:syncShopAdInfo(player)
    self:syncGiftAdInfo(player)
    self:syncChestAdInfo(player)
    self:syncVipAdInfo(player)
end

function AdvertConfig:getGoldAdByTimes(times)
    if times <= 0 then
        return nil
    end
    if times > #self.GoldAds then
        return nil
    end
    return self.GoldAds[times]
end

