function AdvertConfig:doGoldAdReward(player)
    local times = player.advert_record.GoldAdTimes + 1
    local advert = AdvertConfig:getGoldAdByTimes(times)
    if not advert then
        return
    end
    player:addCurrency(advert.count)
    player.advert_record.GoldAdTimes = times
    self:syncGoldAdInfo(player)
    GamePacketSender:sendPixelGunGoldAdReward(player.rakssid, advert.count, times, #self.GoldAds)
end

function AdvertConfig:doShopAdReward(player)
    local times = player.advert_record.ShopAdTimes + 1
    local advert = AdvertConfig:getShopAdByTimes(times)
    if not advert then
        return
    end
    GameChestLottery:onPlayerRewardVip(player, advert.count)
    player.advert_record.ShopAdTimes = times
    self:syncShopAdInfo(player)
    HostApi.notifyGetGoods(player.rakssid, "set:game_props.json image:prop_vip", 1)
end

function AdvertConfig:doGiftAdReward(player)
    local times = player.advert_record.GiftAdTimes + 1
    local advert = AdvertConfig:getGiftAdByTimes(times)
    if not advert then
        return
    end
    player.advert_record.GiftAdTimes = times
    player.giftBagController:refreshGiftBags()
    self:syncGiftAdInfo(player)
end

function AdvertConfig:doTaskAdReward(player, taskId)
    if player == nil then
        return
    end
    player.taskController:receiveTaskDoubleReward(taskId)
end

function AdvertConfig:doChestAdReward(player)
    local times = player.advert_record.ChestAdTimes + 1
    local advert = AdvertConfig:getChestAdByTimes(times)
    if not advert then
        return
    end
    local reward = RewardConfig:getRewardById(advert.count)
    player.advert_record.ChestAdTimes = times
    self:syncChestAdInfo(player)
    if not reward then
        return
    end
    GameReward:onPlayerGetReward(player, reward)
    GamePacketSender:sendPixelGunRewardResult(player.rakssid, reward.Id)
end

function AdvertConfig:doVipAdReward(player)
    local times = player.advert_record.VipAdTimes + 1
    local advert = AdvertConfig:getVipAdByTimes(times)
    if not advert then
        return
    end
    local reward = RewardConfig:getRewardById(advert.count)
    player.advert_record.VipAdTimes = times
    self:syncVipAdInfo(player)
    if not reward then
        return
    end
    GameReward:onPlayerGetReward(player, reward)
end

