function AdvertConfig:syncGiftAdInfo(player)
    player.advert_record.GiftAdTimes = player.advert_record.GiftAdTimes or 0
    local times = #self.GiftAds - player.advert_record.GiftAdTimes
    local advert = self:getGiftAdByTimes(player.advert_record.GiftAdTimes + 1)
    local seconds = 0
    if advert then
        seconds = advert.seconds
    end
    GamePacketSender:sendPixelGunGiftBagAd(player.rakssid, times, seconds)
end

function AdvertConfig:syncChestAdInfo(player)
    player.advert_record.ChestAdTimes = player.advert_record.ChestAdTimes or 0
    local times = #self.ChestAds - player.advert_record.ChestAdTimes
    local advert = self:getChestAdByTimes(player.advert_record.ChestAdTimes + 1)
    local seconds = 0
    local reward = 0
    if advert then
        seconds = advert.seconds
        reward = advert.count
    end
    local params = {
        time = seconds,
        times = times,
        rewardId = reward
    }
    local data = DataBuilder.new():fromTable(params):getData()
    PacketSender:sendServerCommonData(player.rakssid, "PixelAdData", "Chest", data)
end

function AdvertConfig:syncVipAdInfo(player)
    player.advert_record.VipAdTimes = player.advert_record.VipAdTimes or 0
    local times = #self.VipAds - player.advert_record.VipAdTimes
    local advert = self:getVipAdByTimes(player.advert_record.VipAdTimes + 1)
    local seconds = 0
    local reward = 0
    if advert then
        seconds = advert.seconds
        reward = advert.count
    end
    local params = {
        time = seconds,
        times = times,
        total = player.advert_record.VipAdTimes .. "/" .. #self.VipAds,
        rewardId = reward
    }
    local data = DataBuilder.new():fromTable(params):getData()
    PacketSender:sendServerCommonData(player.rakssid, "PixelAdData", "Vip", data)
end

return AdvertConfig